import{_ as r,o as e,c as a,ae as o}from"./chunks/framework.DAK3ioSj.js";const c=JSON.parse('{"title":"SkillReducer","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillreducer.md","filePath":"radar/tech-skillreducer.md"}'),l={name:"radar/tech-skillreducer.md"};function i(s,t,d,n,h,u){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="skillreducer" tabindex="-1">SkillReducer <a class="header-anchor" href="#skillreducer" aria-label="Permalink to &quot;SkillReducer&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 优化 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.55</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: 在 <strong>600 个 Skill + SkillsBench</strong> 实证揭示 Skill 生态系统性冗余 —— description 压缩 48% + body 压缩 39%，<strong>功能质量反升 2.8%</strong>（less-is-more 效应）。</p><p><strong>来源</strong>:</p><ul><li>学术研究 - 港科大等</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2603.29919" target="_blank" rel="noreferrer">arXiv 2603.29919</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="实证发现" tabindex="-1">实证发现 <a class="header-anchor" href="#实证发现" aria-label="Permalink to &quot;实证发现&quot;">​</a></h3><p>研究样本：<strong>600 个公开 Skill + SkillsBench 任务套</strong>。</p><table tabindex="0"><thead><tr><th>发现</th><th>数据</th></tr></thead><tbody><tr><td><strong>没写 description 的 Skill</strong></td><td>26.4%</td></tr><tr><td><strong>body 中&quot;非可操作&quot;内容</strong></td><td>60%+</td></tr><tr><td><strong>reference 文件注入量</strong></td><td>数万 Token</td></tr></tbody></table><h3 id="stage-1-—-路由层优化-delta-debugging" tabindex="-1">Stage 1 — 路由层优化（Delta Debugging） <a class="header-anchor" href="#stage-1-—-路由层优化-delta-debugging" aria-label="Permalink to &quot;Stage 1 — 路由层优化（Delta Debugging）&quot;">​</a></h3><p>用对抗性方法找 description 的&quot;最小充分子集&quot;。</p><blockquote><p>你有一串 50 个关键词的 description，SkillReducer 逐个删除测试&quot;Agent 还能正确找到这个 Skill 吗？&quot;，最终压缩到只留最关键的 10 个词。压缩率 <strong>48%</strong>。</p></blockquote><h3 id="stage-2-—-body-重构-渐进披露" tabindex="-1">Stage 2 — Body 重构（渐进披露） <a class="header-anchor" href="#stage-2-—-body-重构-渐进披露" aria-label="Permalink to &quot;Stage 2 — Body 重构（渐进披露）&quot;">​</a></h3><p>Skill body 分层：</p><ul><li><strong>核心规则</strong>（永远加载） —— 如&quot;组件必须是纯函数&quot;</li><li><strong>背景知识 + 示例</strong>（按需加载） —— 如&quot;关于 React Hooks 的历史&quot;</li></ul><p>Agent 默认只看&quot;首页&quot;，需要时才翻&quot;文件柜&quot;。压缩率 <strong>39%</strong>。</p><h3 id="less-is-more-效应" tabindex="-1">&quot;Less-is-more&quot; 效应 <a class="header-anchor" href="#less-is-more-效应" aria-label="Permalink to &quot;&quot;Less-is-more&quot; 效应&quot;">​</a></h3><p>压缩后功能质量反而 <strong>+2.8%</strong> —— 干扰 Agent 注意力的噪音少了。在四个家族五个模型上迁移有效。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>聚焦<strong>静态压缩</strong>（让已有 Skill 更精简），<strong>不涉及 Skill 内容进化或新 Skill 发现</strong></li><li>压缩是通用的，不针对特定失败模式做定向优化</li><li>仍是学术论文阶段，<strong>未产品化</strong></li><li>未做&quot;基于当前任务的动态按需加载&quot;</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.65</td><td>55K 大规模实证 + 多模型迁移验证</td></tr><tr><td>创新性</td><td>0.70</td><td>less-is-more 是反共识发现</td></tr><tr><td>落地程度</td><td>0.40</td><td>论文阶段，需工程化为 Skill Lint 工具</td></tr><tr><td>生态活跃度</td><td>0.40</td><td>学术</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.55</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2603.29919" target="_blank" rel="noreferrer">SkillReducer 论文</a></li></ul>',34)])])}const b=r(l,[["render",i]]);export{c as __pageData,b as default};
